const { regular, classic, icons } = await loadFonts();
  const { name, phone, address, logo } = brandData;
  const scale = getScale(width, height);

  const footerH = 180 * scale;
  const paint = Skia.Paint();

  // Dark overlay gradient for the bottom
  const colors = [Skia.Color('transparent'), Skia.Color('rgba(0,0,0,0.9)')];
  paint.setShader(Skia.Shader.MakeLinearGradient({ x: 0, y: height - footerH - 100*scale }, { x: 0, y: height }, colors, [0, 1], 0));
  canvas.drawRect({ x: 0, y: height - footerH - 100*scale, width, height: footerH + 100*scale }, paint);
  paint.setShader(null);

  // Agent Name (Classic/Serif)
  paint.setColor(Skia.Color('white'));
  const nameFont = classic;
  nameFont.setSize(45 * scale);
  drawTextLeft(canvas, name.toUpperCase(), 50 * scale, height - 100 * scale, nameFont, paint, width - (40 * scale));

  // Address (Thin/Minimal)
  const addrFont = regular;
  addrFont.setSize(22 * scale);
  paint.setColor(Skia.Color('#CCCCCC'));
  if (address) drawTextLeft(canvas, address, 50 * scale, height - 60 * scale, addrFont, paint, width - (40 * scale));

  // Vertical Divider
  paint.setColor(Skia.Color('white'));
  canvas.drawRect({ x: width * 0.7, y: height - 130*scale, width: 2*scale, height: 80*scale }, paint);

  // Company Logo (Right of divider)
  if (logo) {
    const lSize = 100 * scale;
    drawLogo(canvas, logo, width * 0.75, height - 130*scale, lSize, lSize * (getLogoDimensions(logo).height / getLogoDimensions(logo).width));
  }

  return ["name", "address", "logoUri"];

