  const nFont = bold;
  nFont.setSize(32 * scale);
  drawTextLeft(canvas, name, width - sideW + 30*scale, 80*scale, nFont, paint, width - (40 * scale));

  const itemFont = regular;
  itemFont.setSize(20 * scale);
  const startY = 160 * scale;
  const gap = 80 * scale;

  const items = [
    { icon: 'call', text: phone },
    { icon: 'mail', text: email },
    { icon: 'globe', text: website }
