const { condensed, regular } = await loadFonts();
  const { name, phone } = brandData;
  const scale = getScale(width, height);

  // Red Stamp Center
  const paint = Skia.Paint();
  paint.setColor(Skia.Color('#D32F2F'));
  paint.setStyle(1); // Stroke
  paint.setStrokeWidth(10 * scale);

  const boxW = 500 * scale;
  const boxH = 200 * scale;
  const boxX = (width - boxW)/2;
  const boxY = (height - boxH)/2;

  canvas.save();
  canvas.rotate(-15, width/2, height/2);
  canvas.drawRect({x: boxX, y: boxY, width: boxW, height: boxH}, paint);

  paint.setStyle(0);
  const font = condensed;
  font.setSize(100 * scale);
  const text = "SOLD";
  const tw = font.getTextWidth(text);
  canvas.drawText(text, (width-tw)/2, boxY + 130*scale, paint, font);
  canvas.restore();

  // Footer Agent Info
  paint.setColor(Skia.Color('rgba(0,0,0,0.8)'));
  canvas.drawRect({ x: 0, y: height - 100*scale, width, height: 100*scale }, paint);

  paint.setColor(Skia.Color('white'));
  const af = regular;
  af.setSize(30 * scale);
  drawTextLeft(canvas, `${name} • ${phone}`, 40*scale, height - 40*scale, af, paint, width - (40 * scale));

  return ["name", "phone"];

